package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testToStringArray_nullInput() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Method toStringArray = CSVFormat.class.getDeclaredMethod("toStringArray", Object[].class);
        toStringArray.setAccessible(true);

        Object[] input = null;
        String[] result = (String[]) toStringArray.invoke(csvFormat, (Object) input);
        assertNull(result);
    }

    @Test
    void testToStringArray_emptyArray() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Method toStringArray = CSVFormat.class.getDeclaredMethod("toStringArray", Object[].class);
        toStringArray.setAccessible(true);

        Object[] input = new Object[0];
        String[] result = (String[]) toStringArray.invoke(csvFormat, (Object) input);
        assertNotNull(result);
        assertEquals(0, result.length);
    }

    @Test
    void testToStringArray_arrayWithNullsAndObjects() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Method toStringArray = CSVFormat.class.getDeclaredMethod("toStringArray", Object[].class);
        toStringArray.setAccessible(true);

        Object[] input = new Object[] {null, "test", 123, new Object() {
            @Override
            public String toString() {
                return "customObject";
            }
        }};
        String[] result = (String[]) toStringArray.invoke(csvFormat, (Object) input);
        assertNotNull(result);
        assertEquals(input.length, result.length);
        assertNull(result[0]);
        assertEquals("test", result[1]);
        assertEquals("123", result[2]);
        assertEquals("customObject", result[3]);
    }
}
